#!/usr/bin/env bash
# H Wallet — 一键部署 (真实 OKX Agentic Wallet 接入)
# 把这个文件粘贴进 VPS 的 Web 终端 / SSH 会话执行，跑完打印 HTTPS URL
set -euo pipefail

SERVER_IP="${SERVER_IP:-34.21.193.21}"
DOMAIN="${DOMAIN:-${SERVER_IP//./-}.sslip.io}"
APP_USER="${APP_USER:-ubuntu}"
APP_HOME="$(getent passwd "$APP_USER" | cut -d: -f6)"
DATA_DIR="/var/lib/h-wallet/users"
NODE_MAJOR="${NODE_MAJOR:-20}"

g(){ printf "\033[1;32m%s\033[0m\n" "$*"; }
y(){ printf "\033[1;33m%s\033[0m\n" "$*"; }
r(){ printf "\033[1;31m%s\033[0m\n" "$*"; }

g "==> 1/7 apt 更新 + 基础工具"
sudo apt-get update -y
sudo DEBIAN_FRONTEND=noninteractive apt-get install -y \
  curl wget jq build-essential ca-certificates gnupg \
  debian-keyring debian-archive-keyring apt-transport-https openssl

g "==> 2/7 Node.js ${NODE_MAJOR}"
if ! command -v node >/dev/null 2>&1 || ! node -v | grep -q "^v${NODE_MAJOR}"; then
  curl -fsSL "https://deb.nodesource.com/setup_${NODE_MAJOR}.x" | sudo -E bash -
  sudo apt-get install -y nodejs
fi
node -v && npm -v

g "==> 3/7 onchainos CLI（用户态）"
sudo -u "$APP_USER" bash -lc 'mkdir -p $HOME/.local/bin'
if [ ! -x "$APP_HOME/.local/bin/onchainos" ]; then
  sudo -u "$APP_USER" bash -lc 'curl -sSL https://raw.githubusercontent.com/okx/onchainos-skills/main/install.sh | sh'
fi
sudo -u "$APP_USER" bash -lc 'grep -q "local/bin" $HOME/.bashrc || echo "export PATH=$HOME/.local/bin:$PATH" >> $HOME/.bashrc'
"$APP_HOME/.local/bin/onchainos" --version || { r "onchainos 安装失败"; exit 1; }

g "==> 4/7 写入 walletBackend.js (内嵌)"
sudo mkdir -p "$DATA_DIR"
sudo chown -R "$APP_USER:$APP_USER" "$(dirname "$DATA_DIR")"
WBJS="$APP_HOME/walletBackend.js"
echo "" | base64 -d > "$WBJS"
sudo chown "$APP_USER:$APP_USER" "$WBJS"
chmod 644 "$WBJS"
node -c "$WBJS" && g "  walletBackend.js 语法 OK ($(wc -l < "$WBJS") lines)"

g "==> 5/7 systemd"
SECRET=$(openssl rand -hex 32)
sudo tee /etc/systemd/system/h-wallet.service >/dev/null <<UNIT
[Unit]
Description=H Wallet Backend (onchainos wrapper)
After=network-online.target

[Service]
User=${APP_USER}
WorkingDirectory=${APP_HOME}
Environment=HOME=${APP_HOME}
Environment=PATH=${APP_HOME}/.local/bin:/usr/local/sbin:/usr/local/bin:/usr/sbin:/usr/bin:/sbin:/bin
Environment=ONCHAINOS_BIN=${APP_HOME}/.local/bin/onchainos
Environment=WALLET_DATA_DIR=${DATA_DIR}
Environment=WALLET_PORT=3100
Environment=WALLET_SESSION_SECRET=${SECRET}
ExecStart=/usr/bin/node ${WBJS}
Restart=always
RestartSec=3
StandardOutput=journal
StandardError=journal

[Install]
WantedBy=multi-user.target
UNIT
sudo systemctl daemon-reload
sudo systemctl enable --now h-wallet
sleep 2
sudo systemctl status h-wallet --no-pager | head -20

g "==> 6/7 Caddy + HTTPS"
if ! command -v caddy >/dev/null 2>&1; then
  curl -1sLf 'https://dl.cloudsmith.io/public/caddy/stable/gpg.key' | sudo gpg --batch --yes --dearmor -o /usr/share/keyrings/caddy-stable-archive-keyring.gpg
  curl -1sLf 'https://dl.cloudsmith.io/public/caddy/stable/debian.deb.txt' | sudo tee /etc/apt/sources.list.d/caddy-stable.list >/dev/null
  sudo apt-get update -y
  sudo apt-get install -y caddy
fi
sudo tee /etc/caddy/Caddyfile >/dev/null <<CADDY
${DOMAIN} {
  encode zstd gzip
  reverse_proxy 127.0.0.1:3100
}
CADDY
sudo systemctl restart caddy
sleep 2

g "==> 7/7 防火墙 (如有 ufw)"
if command -v ufw >/dev/null 2>&1 && sudo ufw status | grep -q active; then
  sudo ufw allow 80/tcp || true
  sudo ufw allow 443/tcp || true
fi

g "==> 健康检查"
echo "本机: "
curl -fsS http://127.0.0.1:3100/health | jq . || true
for i in 1 2 3 4 5 6; do
  if curl -fsS "https://${DOMAIN}/health" | jq . ; then
    g "✅  部署完成"
    echo "  Public URL : https://${DOMAIN}"
    echo "  /health    : https://${DOMAIN}/health"
    echo "  日志       : sudo journalctl -u h-wallet -f"
    exit 0
  fi
  y "  等 Caddy 申请证书 ($i/6)..."
  sleep 10
done
r "⚠️  HTTPS 暂未通，请手动检查："
echo "  - 安全组放通 80/443"
echo "  - sudo journalctl -u caddy -n 50"
echo "  - dig ${DOMAIN}"
exit 1
